<span class="line">      ~ <span class="token function">id</span>           <span class="token operator">=</span> <span class="token string">&quot;1&quot;</span> -<span class="token operator">&gt;</span> <span class="token punctuation">(</span>known after apply<span class="token punctuation">)</span></span>
